from agno import Agent
from agno.memory import Memory

class ValidatedMemory(Memory):
    def get(self, key):
        memory = super().get(key)
        # Verify memory exists in conversation history
        if not self._verify_in_history(memory):
            return 'No record found'
        return memory

    def _verify_in_history(self, memory):
        return any(memory in msg for msg in self.messages)

agent = Agent(memory=ValidatedMemory())

